#[inline]
fn get_geoid_val(mut lon_i: i32, lat_i: i32) -> f64 {
    let nlon = (NLON - 1) as i32; // 360 — wrap period
    if lon_i >= nlon {
        lon_i -= nlon;
    } else if lon_i < 0 {
        lon_i += nlon;
    }
    GEOID[lon_i as usize][lat_i as usize] as f64
}

fn cubic_interpolation(p: [f64; 4], x: f64) -> f64 {
    p[1] + 0.5
        * x
        * (p[2] - p[0]
            + x * (2.0 * p[0] - 5.0 * p[1] + 4.0 * p[2] - p[3]
                + x * (3.0 * (p[1] - p[2]) + p[3] - p[0])))
}

fn bilinear_interpolation(ix: i32, iy: i32, fx: f64, fy: f64) -> f64 {
    let sw = get_geoid_val(ix, iy);
    let se = get_geoid_val(ix + 1, iy);
    let nw = get_geoid_val(ix, iy + 1);
    let ne = get_geoid_val(ix + 1, iy + 1);
    (1.0 - fy) * ((1.0 - fx) * sw + fx * se) + fy * ((1.0 - fx) * nw + fx * ne)
}

/// EGM2008 geoid undulation (metres) at the given geodetic position.
///
/// `lat_rad` ∈ \[−π/2, π/2\], `lon_rad` may be negative (west).
/// Returns 0.0 for out-of-range inputs (should not occur for valid Earth positions).
pub fn geoid_undulation_m(lat_rad: f64, lon_rad: f64) -> f64 {
    const R2D: f64 = 180.0 / core::f64::consts::PI;

    let lat_deg = lat_rad * R2D;
    if !(MIN_LAT..=MAX_LAT).contains(&lat_deg) {
        return 0.0;
    }

    let mut lon_deg = lon_rad * R2D;
    if lon_deg < 0.0 {
        lon_deg += 360.0;
    }
    if !(MIN_LON..=MAX_LON).contains(&lon_deg) {
        return 0.0;
    }

    let lat_f = (lat_deg - MIN_LAT) / LAT_STEP;
    let lon_f = (lon_deg - MIN_LON) / LON_STEP;
    let iy_floor = floor(lat_f);
    let ix_floor = floor(lon_f);
    let fy = lat_f - iy_floor;
    let fx = lon_f - ix_floor;
    let ix = ix_floor as i32;
    let iy = iy_floor as i32;

    let lat_max_i = ((MAX_LAT - MIN_LAT) / LAT_STEP) as i32; // 180

    // Special case: exactly at north pole
    if iy == lat_max_i {
        return GEOID[ix as usize][iy as usize] as f64;
    }

    // General case: bicubic interpolation (falls back to bilinear near poles)
    if iy > 0 && iy < lat_max_i - 1 {
        let (y0, y1, y2, y3, fy_interp) = if iy == lat_max_i - 2 {
            (iy + 2, iy + 1, iy, iy - 1, 1.0 - fy)
        } else {
            (iy - 1, iy, iy + 1, iy + 2, fy)
        };

        let cols: [f64; 4] = [
            cubic_interpolation(
                [
                    get_geoid_val(ix - 1, y0),
                    get_geoid_val(ix - 1, y1),
                    get_geoid_val(ix - 1, y2),
                    get_geoid_val(ix - 1, y3),
                ],
                fy_interp,
            ),
            cubic_interpolation(
                [
                    get_geoid_val(ix, y0),
                    get_geoid_val(ix, y1),
                    get_geoid_val(ix, y2),
                    get_geoid_val(ix, y3),
                ],
                fy_interp,
            ),
            cubic_interpolation(
                [
                    get_geoid_val(ix + 1, y0),
                    get_geoid_val(ix + 1, y1),
                    get_geoid_val(ix + 1, y2),
                    get_geoid_val(ix + 1, y3),
                ],
                fy_interp,
            ),
            cubic_interpolation(
                [
                    get_geoid_val(ix + 2, y0),
                    get_geoid_val(ix + 2, y1),
                    get_geoid_val(ix + 2, y2),
                    get_geoid_val(ix + 2, y3),
                ],
                fy_interp,
            ),
        ];
        return cubic_interpolation(cols, fx);
    }

    // Bilinear fallback near poles
    bilinear_interpolation(ix, iy, fx, fy)
}

// fabs imported but only needed if we add magnitude checks; keep for future use
#[allow(dead_code)]
fn _use_fabs(x: f64) -> f64 {
    fabs(x)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn deg2rad(d: f64) -> f64 {
        d * core::f64::consts::PI / 180.0
    }

    #[test]
    fn trondheimsfjord_approx_41m() {
        // EGM2008 at ~63.4°N, 10.4°E ≈ 40–42 m
        let n = geoid_undulation_m(deg2rad(63.4), deg2rad(10.4));
        assert!((38.0..=46.0).contains(&n), "N = {n}");
    }

    #[test]
    fn equator_prime_meridian() {
        let n = geoid_undulation_m(0.0, 0.0);
        assert!((10.0..=25.0).contains(&n), "N = {n}");
    }

    #[test]
    fn north_pole() {
        let n = geoid_undulation_m(deg2rad(90.0), 0.0);
        assert!(n > -200.0 && n < 200.0, "N = {n}");
    }

    #[test]
    fn negative_longitude_wraps() {
        let n_pos = geoid_undulation_m(deg2rad(51.5), deg2rad(350.0));
        let n_neg = geoid_undulation_m(deg2rad(51.5), deg2rad(-10.0));
        assert!((n_pos - n_neg).abs() < 1e-4, "pos={n_pos}, neg={n_neg}");
    }
}
